<template>
    <v-container class="grey lighten-5" fluid>      
      <!-- <v-row class="pa-0" no-gutters>
        <v-col cols="6">
          <ScrollView/>
          <LoadingBar/>   
        </v-col>
      </v-row>    -->

      <v-row class="pa-0" no-gutters>
        <!-- <v-col cols="6">
          <v-card class="pa-0" outlined tile>                                                    
            
            <ImageLayer v-if="readyToShow" :canvasInfo="canvasInfoAxial" ref="Axial"></ImageLayer>
            <DrawLayer v-if="readyToShow"></DrawLayer>
                        
          </v-card>                              
        </v-col> -->

        <v-col cols="12" class="text-center">
          <v-card class="pa-0" outlined tile>    
            <ConnerCanvas/>
          </v-card>    
        </v-col>
      </v-row>    

      
    </v-container>
</template>

<script>
import store from '../../store/store.js'
import ImageLayer from '../../components/ViewContainer/imageLayer.vue'
import DrawLayer from '../../components/ViewContainer/drawLayer.vue'

import LoadingBar from '../../components/Progress/LoadingBar.vue'
import ScrollView from '../../components/ViewContainer/scrollView.vue'

import ConnerCanvas from '../../components/ViewContainer/CornerstoneCanvas.vue'

import axios from "axios"

export default {
  components: { ImageLayer, LoadingBar, ScrollView, DrawLayer, ConnerCanvas },   
  data () {
    return { 
      canvasInfoAxial : {}        
      ,readyToShow : false        
    }
  },  
  mounted() { },
  methods: {
    async loadResource (){
      let apiInfo = store.getters.getApiInfo
      let reqApi = apiInfo.baseDomain + apiInfo.baseSubPath + apiInfo.tagRequestPath
          +"?user=" + apiInfo.user 
          +"&serieUID=" + apiInfo.serieUID 
      //Load Dicom TAG....
      try {
        let result = await axios.get(reqApi)      
        console.log(result)        
        store.commit('tagRetriever/DEFINE_TAG_INFO', result.data)        
        store.dispatch('imageRetriever/defineSrcOfAxial',{})
      } catch (error) {    
        console.log(error)
      }

      //Load Image...      
      var preDefineSerieName = 'AXIAL_HQ'
      let serieHQ = store.getters['imageRetriever/getSerieHQByName'](preDefineSerieName)      
      let imagesHQ = serieHQ.images      
      console.log('Lets Fetch Axial SIZE : ' + imagesHQ.length)
      for(let i = 0; i < 1; i++){
        let sliceIndex = i
        imagesHQ[sliceIndex].onload = () => {
          // console.log(`the image dimensions are ${imagesHQ[sliceIndex].width}
          //   x${imagesHQ[sliceIndex].height}`)                               
          store.commit('imageRetriever/UPDATE_IMAGE_LOAD_SUCCESS', {})
          // if (serieHQ.numLoadDone === serieHQ.numOfSlice) {
            if (serieHQ.numLoadDone === 1) {
            // this.$store.commit('imageRetriever/UPDATE_IMAGE_LOAD_SUCCESS', {})   
            this.readyToShow = true
            let canvasList = this.$store.getters['layout/getCanvasList']
            this.canvasInfoAxial = canvasList[0]               
          }
        }    
      }      
    },
    configLayout: function() {
      var payload = {height:window.innerHeight, width:window.innerWidth};              
      store.dispatch('layout/configAppSize', payload)

      let appSize = store.getters['layout/getAppSize']
      if (appSize.width < 768) {   //Small Device                     
        
      } else {                  
        let grid = {numRow:1, numCol:1}
        store.dispatch('layout/configGrid', grid)        
        // let canvasWidth = appSize.width /grid.numRow
        // let canvasHeight = canvasWidth /grid.numCol
        let canvasWidth = 512
        let canvasHeight = 512
        store.dispatch('layout/configCanvasInfo', {id:'AXIAL',width:canvasWidth, height:canvasHeight})
        store.dispatch('layout/configCanvasInfo', {id:'CORONAL',width:canvasWidth, height:canvasHeight})
        store.dispatch('layout/configCanvasInfo', {id:'SAGITTAL',width:canvasWidth, height:canvasHeight})
        store.dispatch('layout/configCanvasInfo', {id:'3D',width:canvasWidth, height:canvasHeight})
        
        //START Load DicomTag Section...
        this.loadResource()        
      }
    }    
  }
  ,mounted() {  
      this.configLayout()    
    }

}
</script>

<style scoped>
  .text-center {

  }
</style>


