const namespaced = true
const state = {
  tagInfo: {
    resize_scale: 1,
    modality: '',
    number_of_files_resized: 0,
    image_width_resized: 0,
    image_height_resized: 0,
    data_spacing: [],
    image_tranform_width: 0,
    image_tranform_height: 0,
    dicom_manufacturer: ''
  }
}

const mutations = {
  DEFINE_TAG_INFO(state, payload) {
    state.tagInfo.resize_scale = 1
    state.tagInfo.modality = getTagValue(payload['(0008,0060)'])
    state.tagInfo.number_of_files_resized = parseInt(getTagValue(payload['(0054,0081)']))
    state.tagInfo.image_width_resized = parseFloat(getTagValue(payload['(0028,0010)'])) / state.tagInfo.resize_scale
    state.tagInfo.image_height_resized = parseFloat(getTagValue(payload['(0028,0011)'])) / state.tagInfo.resize_scale
    state.tagInfo.data_spacing[0] = parseFloat(getTagValue(payload['(0018,0050)'])) * state.tagInfo.resize_scale
    state.tagInfo.data_spacing[1] = parseFloat(getTagValue(payload['(0018,0050)'])) * state.tagInfo.resize_scale
    state.tagInfo.data_spacing[2] = parseFloat(getTagValue(payload['(0018,0050)'])) * state.tagInfo.resize_scale
    state.tagInfo.image_tranform_width = state.tagInfo.image_width_resized;
    state.tagInfo.image_tranform_height = state.tagInfo.image_height_resized;

    state.tagInfo.dicom_manufacturer = payload['(0008,0080) institution name'];
    console.log(state.tagInfo)
    // ,state.tagInfo.data_spacing = getTagValue(payload['(0018,0050)'])        
    // ,state.tagInfo.image_tranform_width = getTagValue(payload['(0018,0050)'])
    // ,state.tagInfo.image_tranform_height = getTagValue(payload['(0008,0060)'])
  }
}

const actions = {}

const getters = {
  getTagInfo(state) {
    return state.tagInfo
  }
}

function getTagValue(value) {
  return value.substring(value.lastIndexOf("[") + 1, value.lastIndexOf("]"))
}

export default {
  namespaced,
  state,
  mutations,
  actions,
  getters
}



