const namespaced = true
const state = {
  canvasList: [
    { id: 'AXIAL', color: 'red', width: 0, height: 0, sliceIndex: 0 },
    { id: 'CORONAL', color: 'green', width: 0, height: 0 , sliceIndex: 0},
    { id: 'SAGITTAL', color: 'blue', width: 0, height: 0 , sliceIndex: 0},
    { id: '3D', color: 'yellow', width: 0, height: 0 , sliceIndex: 0},
  ],
  grid:{
    numRow: 0, numCol: 0
  },
  // gridList: [ //GRID NUM// ,May be you can remove this
  //   { id: 'ACS',numRow: 2,numCol: 2},
  //   { id: 'FULLSCREEN',numRow: 1,numCol: 1},
  //   { id: 'MATRIX',numRow: 3,numCol: 3}    
  // ],
  displayList : [
    //Will-Added {id:'', viewType:'AXIAL', width:512, height:512}, ...
  ],
  appSize: { width: 0, height: 0 }
}
const mutations = {
  CONFIG_APP_SIZE (state, payload) {
    state.appSize.width = payload.width
    state.appSize.height = payload.height        
  },
  CONFIG_GRID (state, payload) {     
    state.grid.numRow  = payload.numRow
    state.grid.numCol  = payload.numCol
  },
  CONFIG_CANVAS_INFO (state, payload){    
    payload.target_state.width  = payload.width
    payload.target_state.height  = payload.height
  }
}

const actions = {
  configAppSize: ({commit}, payload) => {
    commit('CONFIG_APP_SIZE',  payload )
  },
  configGrid: ({commit}, payload) => {
    commit('CONFIG_GRID',  payload )
  },
  configCanvasInfo: ({commit}, payload) => {
    let id = payload.id

    //Find and commit state
    var itemFound = state.canvasList.find(function(item) {
      return item.id === id
    })
    if(itemFound){ 
      payload["target_state"] = itemFound
      commit('CONFIG_CANVAS_INFO',  payload)
    }
  }  
}

const getters = {  
  getCanvasByName(state) {
    return canvasName => state.canvasInfo.filter(item =>{
      return item.name === canvasName
    })
  },  
  getCanvasList(state){
    // console.log(state.canvasList)
    return state.canvasList
  },

  getAppSize(state){
    return state.appSize
  }
  // getCanvasInfoByName: (state) => (name)  => {
  //   return state.canvasInfo.filter(name => canvasInfo.name === name)
  // },  
  // getRestoDetailById: (state) => (name) => {
  //   return 'ssss'
  // },
  // search(state) { //Function with parameter
  //   return keyword => state.canvasInfo.filter(item =>{
  //     return item.name === keyword
  //   })
  // }
}

export default {
  namespaced,
  state,
  mutations,
  actions,
  getters
}




