<template>
  <section>    
    <v-container>
      <v-row>      
        <v-col cols="12">      
          <div>{{sliceIndex}}</div>
          <canvas ref="imageLayer" id="imageLayer">
          </canvas>
        </v-col>
      </v-row>
    </v-container>    
  </section>    
</template>

<script>
// import store from '../../store/store.js'
// import {mapGetters} from 'vuex'
export default { 
  props: ["canvasInfo"],     
  data () {
    return {        
      serieID : "AXIAL_HQ"  
    }
  },  
  computed: {
    sliceIndex: function(){
      let serieMatch = this.$store.getters['imageRetriever/getSerieHQByName']('AXIAL_HQ')                  
      return serieMatch.currentSliceIndex
    }
  },
  watch: {
    sliceIndex: function(newVal, oldVal){
      this.drawHighQImage()
    }
  },   
  methods: {    
    configCanvasInfo: function() {  
      var canv = this.$refs['imageLayer']                  
      var ctx = canv.getContext('2d')
      let dcmTagInfo = this.$store.getters['tagRetriever/getTagInfo']
      ctx.canvas.width  = dcmTagInfo.image_width_resized      
      ctx.canvas.height = dcmTagInfo.image_height_resized      
    },
    drawLowQImage: function(){      
    },
    drawHighQImage: function(){
      console.log("DrawHighQImage.............!")
      let seriesHQ = this.$store.getters['imageRetriever/getSeriesHQList']
      let a_slices = seriesHQ[0].images[this.sliceIndex]
      
      var canv = this.$refs['imageLayer']   
      var ctx = canv.getContext('2d')      

      let dcmTagInfo = this.$store.getters['tagRetriever/getTagInfo']
      ctx.canvas.width  = dcmTagInfo.image_width_resized
      ctx.canvas.height = dcmTagInfo.image_height_resized

      ctx.clearRect(0, 0, this.canvasInfo.width, this.canvasInfo.height)
      ctx.drawImage(a_slices, 0, 0)
    },
  },
  mounted() { 
    console.log("COME MOUNT <ViewCanvas!>")     
    this.configCanvasInfo()  
    this.drawHighQImage()    
  }
}

</script>

<style>

#imageLayer {position: absolute; left: 0%; top: 0%;}
/* #imageLayer { 
  position: absolute;
 } */
/* #imageLayer { */
  /* width: 100%;
  height: 100%; */
/* } */
</style>



