<template>
  <div>
    <v-navigation-drawer
      v-model="drawer"
      absolute
      temporary
    >
      <v-list-item>
        <v-list-item-avatar>
          <v-img src="https://randomuser.me/api/portraits/men/78.jpg"></v-img>
        </v-list-item-avatar>

        <v-list-item-content>
          <v-list-item-title>2D VIEWER</v-list-item-title>
        </v-list-item-content>
      </v-list-item>

      <v-divider></v-divider>

      <v-list dense>
        <v-list-item link>
          <v-list-item-icon>
            <v-icon>mdi-information-outline</v-icon>
          </v-list-item-icon>
          <v-list-item-content>
            <v-list-item-title>Information</v-list-item-title>
          </v-list-item-content>
        </v-list-item>
        <v-list-item link @click="zoomButtonHandler" :class="{'actived-nav': onZoomActived}">
          <v-list-item-icon>
            <v-icon>mdi-magnify-plus-outline</v-icon>
          </v-list-item-icon>
          <v-list-item-content>
            <v-list-item-title>Zoom +/-</v-list-item-title>
          </v-list-item-content>
        </v-list-item>
        <v-list-item link @click="lengthButtonHandler" :class="{'actived-nav': onLengthActived}">
          <v-list-item-icon>
            <v-icon>mdi-ruler</v-icon>
          </v-list-item-icon>
          <v-list-item-content>
            <v-list-item-title>Length measurement</v-list-item-title>
          </v-list-item-content>
        </v-list-item>
        <v-list-item link @click="angleButtonHandler" :class="{'actived-nav': onAngleActived}">
          <v-list-item-icon>
            <v-icon>mdi-angle-acute</v-icon>
          </v-list-item-icon>
          <v-list-item-content>
            <v-list-item-title>Angle</v-list-item-title>
          </v-list-item-content>
        </v-list-item>
        <!-- <v-list-item
          v-for="item in items"
          :key="item.title"
          link
        >
          <v-list-item-icon>
            <v-icon>{{ item.icon }}</v-icon>
          </v-list-item-icon>

          <v-list-item-content>
            <v-list-item-title>{{ item.title }}</v-list-item-title>
          </v-list-item-content>
        </v-list-item> -->
      </v-list>
    </v-navigation-drawer>
    
    <v-toolbar
      :extended="false"
      :prominent="false"
      :dense="true"
      :collapse="false"
      :flat="false"
      :extension-height="extensionHeight"
      :height="height"
      dark
      class="primary"
    >
      <v-app-bar-nav-icon v-if="!$vuetify.breakpoint.smAndUp" @click.stop="drawer = !drawer"></v-app-bar-nav-icon>
      <v-toolbar-title>2D VIEWER</v-toolbar-title>
      <!-- <div class="flex-grow-1"></div> -->
      <v-spacer></v-spacer>
      <template v-if="$vuetify.breakpoint.smAndUp">
        <v-btn icon>
          <v-icon>mdi-information-outline</v-icon>
        </v-btn>
        <v-btn icon @click="zoomButtonHandler" :class="{actived: onZoomActived}">
          <v-icon>mdi-magnify-plus-outline</v-icon>
        </v-btn>
        <v-btn icon @click="lengthButtonHandler" :class="{actived: onLengthActived}">
          <v-icon>mdi-ruler</v-icon>
        </v-btn>
        <v-btn icon @click="angleButtonHandler" :class="{actived: onAngleActived}">
          <v-icon>mdi-angle-acute</v-icon>
        </v-btn>
      </template>
    </v-toolbar>    
  </div>  
</template>

<script>
  export default {
    data() {
      return {
        drawer: false,
        extended: false,
        extendedSlot: false,
        prominent: false,
        dense: false,
        collapse: false,
        flat: false,
        bg: false,
        extensionHeight: 0,
        height: 0,
        onZoomActived: false,
        onLengthActived: false,
        onAngleActived: false,
      }
    },
    mounted() {  
      let appUiInfo = this.$store.getters.getAppUiInfo
      this.height = appUiInfo.toolboxHeight
      console.log('this.height : ' + this.height)
    },
    methods: { 
      zoomButtonHandler() {
        if (this.$store.state.flagMode != 'ZOOM') {
          this.onZoomActived = true
          this.onLengthActived = false
          this.onAngleActived = false
          this.drawer = false
          this.$store.commit('SET_FLAG_MODE', { flagMode: 'ZOOM' })
        } else {
          this.onZoomActived = false
          this.$store.commit('SET_FLAG_MODE', { flagMode: '' })
        }
      },
      lengthButtonHandler() {
        if (this.$store.state.flagMode != 'LENGTH') {
          this.onZoomActived = false
          this.onLengthActived = true
          this.onAngleActived = false
          this.drawer = false
          this.$store.commit('SET_FLAG_MODE', { flagMode: 'LENGTH' })
        } else {
          this.onLengthActived = false
          this.$store.commit('SET_FLAG_MODE', { flagMode: '' })
        }
      },
      angleButtonHandler() {
        if (this.$store.state.flagMode != 'ANGLE') {
          this.onZoomActived = false
          this.onLengthActived = false
          this.onAngleActived = true
          this.drawer = false
          this.$store.commit('SET_FLAG_MODE', { flagMode: 'ANGLE' })
        } else {
          this.onAngleActived = false
          this.$store.commit('SET_FLAG_MODE', { flagMode: '' })
        }
      }
    }
}
</script>

<style scoped>
  .actived.theme--dark.v-btn.v-btn--icon {
    background-color: #b6d2eec0;
  }
  .actived-nav {
    background-color: aqua;
  }
</style>


